  ('elementary-d0d1b9a2-moex-00857', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '將收益支出誤記為資本支出，對當年度報表之影響為：', '["淨利低估，資產低估", "淨利高估，資產高估", "淨利低估，資產高估", "淨利高估，資產低估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
