  ('elementary-d0d1b9a2-moex-00859', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於 9 月份開立一張支票給乙公司，此張支票於 11 月份才兌現，此一交易事項對甲公司在編製 10 月份以正確餘額為準之銀行存款調節表時，應如何處理？', '["列為銀行對帳單餘額的減項", "列為銀行對帳單餘額的加項", "列為公司帳載現金餘額的減項", "不須調整"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
